"""
TF Tracker - Seed Script
Populates the database with all Transformers series and figures.
Run ONCE after first install: python seed.py
Safe to re-run - skips already existing robots.
"""
import sqlite3, uuid, os, sys

DB_PATH = os.path.join(os.path.dirname(os.path.abspath(__file__)), "tracker.db")

def uid(): return str(uuid.uuid4())

def seed():
    db = sqlite3.connect(DB_PATH)
    db.execute("PRAGMA foreign_keys = ON")
    db.row_factory = sqlite3.Row
    db.executescript("""
        CREATE TABLE IF NOT EXISTS series (
            id TEXT PRIMARY KEY, name TEXT NOT NULL UNIQUE,
            short_name TEXT NOT NULL, years TEXT, sort_order INTEGER DEFAULT 0);
        CREATE TABLE IF NOT EXISTS robots (
            id TEXT PRIMARY KEY, name TEXT NOT NULL, category TEXT DEFAULT "",
            combiner TEXT DEFAULT "", instance TEXT DEFAULT "",
            sort_order INTEGER DEFAULT 0, open INTEGER DEFAULT 0,
            img_file TEXT, faction TEXT DEFAULT "",
            series_id TEXT REFERENCES series(id),
            created_at TEXT DEFAULT (datetime("now")));
        CREATE TABLE IF NOT EXISTS accessories (
            id TEXT PRIMARY KEY,
            robot_id TEXT NOT NULL REFERENCES robots(id) ON DELETE CASCADE,
            name TEXT NOT NULL, qty INTEGER DEFAULT 1, have INTEGER DEFAULT 0,
            combiner_part INTEGER DEFAULT 0, size TEXT DEFAULT "",
            img_file TEXT, sort_order INTEGER DEFAULT 0);
        CREATE INDEX IF NOT EXISTS idx_robots_series ON robots(series_id);
        CREATE INDEX IF NOT EXISTS idx_robots_faction ON robots(faction);
        CREATE INDEX IF NOT EXISTS idx_acc_robot ON accessories(robot_id);
    """)
    total_series = total_robots = total_accs = 0

    # Generation 1
    _s = db.execute("SELECT id FROM series WHERE short_name=?", ('G1',)).fetchone()
    if not _s:
        _sid = uid()
        db.execute("INSERT INTO series (id,name,short_name,years,sort_order) VALUES (?,?,?,?,?)",
            (_sid, 'Generation 1', 'G1', '1984-1990', 1))
        total_series += 1
